//! src/error.rs
//!
//! Unified Application Error Type for LedgerLink Nexus
//!
//! This module provides a centralized error handling mechanism for the entire
//! application. It consolidates the various error handling patterns that were
//! previously scattered across different modules (String errors, anyhow::Error,
//! custom error structs) into a single, robust, and expressive AppError type.
//!
//! Key Features:
//! - Implements std::error::Error and std::fmt::Display via thiserror
//! - Provides From<T> conversions for common error types (sqlx, redis, etc.)
//! - Implements axum::response::IntoResponse for HTTP error responses
//! - Maps each variant to appropriate HTTP status codes
//! - Returns consistent JSON error envelopes

use axum::{
    http::StatusCode,
    response::{IntoResponse, Response},
    Json,
};
use serde::Serialize;
use serde_json::json;
use thiserror::Error;

/// Unified application error type that represents all failure modes in
/// the LedgerLink Nexus microservice.
///
/// This enum consolidates error handling across the entire application,
/// providing consistent error responses and appropriate HTTP status codes.
#[derive(Debug, Error)]
pub enum AppError {
    /// Validation errors for invalid user input or request parameters.
    /// Maps to HTTP 400 Bad Request.
    #[error("Validation Error: {0}")]
    ValidationError(String),

    /// Resource not found errors.
    /// Maps to HTTP 404 Not Found.
    #[error("Resource Not Found: {0}")]
    NotFound(String),

    /// Authentication failures - user is not authenticated.
    /// Maps to HTTP 401 Unauthorized.
    #[error("Authentication Failed")]
    Unauthorized,

    /// Authorization failures - user lacks required permissions.
    /// Maps to HTTP 403 Forbidden.
    #[error("Access Denied: {0}")]
    Forbidden(String),

    /// Database errors from sqlx operations.
    /// Maps to HTTP 500 Internal Server Error.
    #[error("Database Error: {0}")]
    Database(#[from] sqlx::Error),

    /// Cache errors from Redis operations.
    /// Maps to HTTP 500 Internal Server Error (or degraded service).
    #[error("Cache Error: {0}")]
    Cache(#[from] redis::RedisError),

    /// Serialization/deserialization errors.
    /// Maps to HTTP 500 Internal Server Error.
    #[error("Serialization Error: {0}")]
    Serialization(#[from] serde_json::Error),

    /// Pagination errors for invalid page parameters.
    /// Maps to HTTP 400 Bad Request.
    #[error("Pagination Error: {0}")]
    PaginationError(String),

    /// Repository-level errors that don't fit other categories.
    /// Maps to HTTP 500 Internal Server Error.
    #[error("Repository Error: {0}")]
    Repository(String),

    /// Generic internal server errors for unexpected conditions.
    /// Maps to HTTP 500 Internal Server Error.
    #[error("Internal Server Error: {0}")]
    Internal(String),

    /// Wraps anyhow::Error for backward compatibility with existing code.
    /// Maps to HTTP 500 Internal Server Error.
    #[error("Internal Error: {0}")]
    Anyhow(#[from] anyhow::Error),

    /// Validator crate validation errors.
    /// Maps to HTTP 400 Bad Request.
    #[error("Validation Error: {0}")]
    ValidatorError(#[from] validator::ValidationErrors),

    /// Timeout errors for long-running operations.
    /// Maps to HTTP 504 Gateway Timeout.
    #[error("Operation Timeout: {0}")]
    Timeout(String),

    /// Rate limiting errors.
    /// Maps to HTTP 429 Too Many Requests.
    #[error("Rate Limit Exceeded: {0}")]
    RateLimitExceeded(String),

    /// Service unavailable errors.
    /// Maps to HTTP 503 Service Unavailable.
    #[error("Service Unavailable: {0}")]
    ServiceUnavailable(String),
}

/// Structured JSON error response body.
#[derive(Debug, Serialize)]
pub struct ErrorResponse {
    pub error: ErrorDetail,
}

/// Details of the error for structured JSON response.
#[derive(Debug, Serialize)]
pub struct ErrorDetail {
    /// Error type identifier (e.g., "validation", "not_found", "unauthorized")
    #[serde(rename = "type")]
    pub error_type: String,
    /// Human-readable error message
    pub message: String,
}

impl AppError {
    /// Returns the appropriate HTTP status code for this error variant.
    pub fn status_code(&self) -> StatusCode {
        match self {
            AppError::ValidationError(_) => StatusCode::BAD_REQUEST,
            AppError::NotFound(_) => StatusCode::NOT_FOUND,
            AppError::Unauthorized => StatusCode::UNAUTHORIZED,
            AppError::Forbidden(_) => StatusCode::FORBIDDEN,
            AppError::Database(_) => StatusCode::INTERNAL_SERVER_ERROR,
            AppError::Cache(_) => StatusCode::INTERNAL_SERVER_ERROR,
            AppError::Serialization(_) => StatusCode::INTERNAL_SERVER_ERROR,
            AppError::PaginationError(_) => StatusCode::BAD_REQUEST,
            AppError::Repository(_) => StatusCode::INTERNAL_SERVER_ERROR,
            AppError::Internal(_) => StatusCode::INTERNAL_SERVER_ERROR,
            AppError::Anyhow(_) => StatusCode::INTERNAL_SERVER_ERROR,
            AppError::ValidatorError(_) => StatusCode::BAD_REQUEST,
            AppError::Timeout(_) => StatusCode::GATEWAY_TIMEOUT,
            AppError::RateLimitExceeded(_) => StatusCode::TOO_MANY_REQUESTS,
            AppError::ServiceUnavailable(_) => StatusCode::SERVICE_UNAVAILABLE,
        }
    }

    /// Returns the error type string for structured JSON responses.
    pub fn error_type(&self) -> &'static str {
        match self {
            AppError::ValidationError(_) => "validation",
            AppError::NotFound(_) => "not_found",
            AppError::Unauthorized => "unauthorized",
            AppError::Forbidden(_) => "forbidden",
            AppError::Database(_) => "database",
            AppError::Cache(_) => "cache",
            AppError::Serialization(_) => "serialization",
            AppError::PaginationError(_) => "pagination",
            AppError::Repository(_) => "repository",
            AppError::Internal(_) => "internal",
            AppError::Anyhow(_) => "internal",
            AppError::ValidatorError(_) => "validation",
            AppError::Timeout(_) => "timeout",
            AppError::RateLimitExceeded(_) => "rate_limit",
            AppError::ServiceUnavailable(_) => "service_unavailable",
        }
    }

    /// Creates a structured error response.
    pub fn to_error_response(&self) -> ErrorResponse {
        ErrorResponse {
            error: ErrorDetail {
                error_type: self.error_type().to_string(),
                message: self.to_string(),
            },
        }
    }
}

/// Implement IntoResponse for axum compatibility.
/// This allows AppError to be returned directly from handlers.
impl IntoResponse for AppError {
    fn into_response(self) -> Response {
        let status = self.status_code();
        let body = Json(self.to_error_response());

        (status, body).into_response()
    }
}

/// Type alias for Results using AppError.
pub type AppResult<T> = Result<T, AppError>;

// Additional From implementations for common error types

impl From<String> for AppError {
    fn from(s: String) -> Self {
        AppError::Internal(s)
    }
}

impl From<&str> for AppError {
    fn from(s: &str) -> Self {
        AppError::Internal(s.to_string())
    }
}

impl From<std::io::Error> for AppError {
    fn from(err: std::io::Error) -> Self {
        AppError::Internal(err.to_string())
    }
}

impl From<tokio_postgres::Error> for AppError {
    fn from(err: tokio_postgres::Error) -> Self {
        AppError::Repository(err.to_string())
    }
}

// Helper constructors for common error scenarios

impl AppError {
    /// Creates a validation error with the given message.
    pub fn validation<S: Into<String>>(msg: S) -> Self {
        AppError::ValidationError(msg.into())
    }

    /// Creates a not found error for a specific resource.
    pub fn not_found<S: Into<String>>(resource: S) -> Self {
        AppError::NotFound(resource.into())
    }

    /// Creates an unauthorized error.
    pub fn unauthorized() -> Self {
        AppError::Unauthorized
    }

    /// Creates a forbidden error with reason.
    pub fn forbidden<S: Into<String>>(reason: S) -> Self {
        AppError::Forbidden(reason.into())
    }

    /// Creates a repository error with message.
    pub fn repository<S: Into<String>>(msg: S) -> Self {
        AppError::Repository(msg.into())
    }

    /// Creates an internal error with message.
    pub fn internal<S: Into<String>>(msg: S) -> Self {
        AppError::Internal(msg.into())
    }

    /// Creates a pagination error with message.
    pub fn pagination<S: Into<String>>(msg: S) -> Self {
        AppError::PaginationError(msg.into())
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_validation_error_status_code() {
        let err = AppError::ValidationError("Invalid input".to_string());
        assert_eq!(err.status_code(), StatusCode::BAD_REQUEST);
        assert_eq!(err.error_type(), "validation");
    }

    #[test]
    fn test_not_found_error_status_code() {
        let err = AppError::NotFound("User not found".to_string());
        assert_eq!(err.status_code(), StatusCode::NOT_FOUND);
        assert_eq!(err.error_type(), "not_found");
    }

    #[test]
    fn test_unauthorized_error_status_code() {
        let err = AppError::Unauthorized;
        assert_eq!(err.status_code(), StatusCode::UNAUTHORIZED);
        assert_eq!(err.error_type(), "unauthorized");
    }

    #[test]
    fn test_error_response_structure() {
        let err = AppError::ValidationError("Invalid ID".to_string());
        let response = err.to_error_response();

        assert_eq!(response.error.error_type, "validation");
        assert!(response.error.message.contains("Invalid ID"));
    }

    #[test]
    fn test_from_string() {
        let err: AppError = "Something went wrong".into();
        assert!(matches!(err, AppError::Internal(_)));
    }

    #[test]
    fn test_helper_constructors() {
        let validation = AppError::validation("Bad input");
        assert!(matches!(validation, AppError::ValidationError(_)));

        let not_found = AppError::not_found("Resource");
        assert!(matches!(not_found, AppError::NotFound(_)));

        let unauthorized = AppError::unauthorized();
        assert!(matches!(unauthorized, AppError::Unauthorized));
    }
}
