   402→            req.page = 1;
   403→        }
   404→        if req.per_page == 0 {
   405→            req.per_page = 32;
   406→        }
   407→
   408→        // Validate.
   409→        req.validate()?;
   410→
   411→        let cache_key = compute_cache_key(tenant_id, &req);
   412→        if let Some(cached) = self.cache.get_page(&cache_key).await? {
   413→            trace!("cache_hit key={}", &cache_key);
   414→            let resp: LedgerEntryPageResponse = serde_json::from_str(&cached)?;
