    55→/////////////////////////////////////////////////////////////////////////////
    56→// 2. PAGINATION
    57→/////////////////////////////////////////////////////////////////////////////
    58→
    59→mod pagination {
    60→    //! Cursor-based pagination utilities.
    61→    //!
    62→    //! LedgerLink Nexus supports both page-number & cursor styles, however the
    63→    //! latter is recommended for high-volume tables because it is stable with
    64→    //! concurrent inserts.  We expose a minimal but production-ready subset
    65→    //! here.
    66→
    67→    use super::*;
    68→    use serde::de::Error as DeError;
    69→    use serde::{Deserializer, Serializer};
    70→
    71→    /// Input parameters from the client.  Either `after` or `before` acts as a
    72→    /// cursor (opaque to the caller), combined with a positive `limit`.
    73→    #[derive(Debug, Clone, Serialize, Deserialize)]
    74→    pub struct PageParams {
    75→        #[serde(default, skip_serializing_if = "Option::is_none")]
    76→        pub after: Option<String>,
    77→        #[serde(default, skip_serializing_if = "Option::is_none")]
    78→        pub before: Option<String>,
    79→        #[serde(default = "PageParams::default_limit")]
    80→        pub limit: u32,
    81→    }
    82→
    83→    impl PageParams {
    84→        const MAX_LIMIT: u32 = 500;
    85→
    86→        fn default_limit() -> u32 {
    87→            100
    88→        }
    89→
    90→        /// Sanity-check – guarantee reasonable values before we hit the DB.
    91→        pub fn validate(&self) -> Result<(), PageError> {
    92→            if self.after.is_some() && self.before.is_some() {
    93→                return Err(PageError::AmbiguousCursors);
    94→            }
    95→            if self.limit == 0 || self.limit > Self::MAX_LIMIT {
    96→                return Err(PageError::InvalidLimit(self.limit));
    97→            }
    98→            Ok(())
    99→        }
   100→    }
   101→
   102→    #[derive(Debug, Error)]
   103→    pub enum PageError {
   104→        #[error("both 'after' and 'before' cursors supplied – choose one")]
   105→        AmbiguousCursors,
   106→        #[error("limit of {0} outside allowed range")]
   107→        InvalidLimit(u32),
   108→    }
   109→
   110→    /// Outgoing envelope – contains the requested slice and cursors for the
   111→    /// caller to request the next/previous page.
   112→    #[derive(Debug, Clone, Serialize, Deserialize)]
   113→    pub struct Paged<T> {
   114→        pub data: Vec<T>,
   115→        #[serde(serialize_with = "serialize_cursor_opt")]
   116→        #[serde(deserialize_with = "deserialize_cursor_opt")]
   117→        pub next: Option<String>,
   118→        #[serde(serialize_with = "serialize_cursor_opt")]
   119→        #[serde(deserialize_with = "deserialize_cursor_opt")]
   120→        pub prev: Option<String>,
   121→    }
   122→
   123→    // --- Cursor helpers ---------------------------------------------------
   124→
   125→    fn serialize_cursor_opt<S>(value: &Option<Vec<u8>>, ser: S) -> Result<S::Ok, S::Error>
   126→    where
   127→        S: Serializer,
   128→    {
   129→        match value {
   130→            Some(bytes) => ser.serialize_some(&base64::encode(bytes)),
   131→            None => ser.serialize_none(),
   132→        }
   133→    }
   134→
   135→    fn deserialize_cursor_opt<'de, D>(de: D) -> Result<Option<Vec<u8>>, D::Error>
   136→    where
   137→        D: Deserializer<'de>,
   138→    {
   139→        let opt: Option<String> = Option::deserialize(de)?;
   140→        opt.map(|s| base64::decode(s).map_err(DeError::custom))
   141→            .transpose()
   142→    }
   143→
   144→    impl<T> Paged<T> {
   145→        pub fn empty() -> Self {
   146→            Self {
   147→                data: Vec::new(),
   148→                next: None,
   149→                prev: None,
   150→            }
   151→        }
   152→    }
   153→}
