   182→
   183→/// A very small caching trait; in the real service this would expose more
   184→/// fine-grained TTL control, eviction metrics, tracing, etc.
   185→#[async_trait]
   186→pub trait Cache: Send + Sync {
   187→    async fn get_bytes(&self, key: &str) -> anyhow::Result<Option<Vec<u8>>>;
   188→    async fn set_bytes(&self, key: &str, value: &[u8], ttl: Duration) -> anyhow::Result<()>;
   189→}
   190→
   191→/// In-memory stub used in unit/integration tests.
   192→pub struct MemoryCache {
   193→    store: RwLock<std::collections::HashMap<String, (Vec<u8>, std::time::Instant)>>,
   194→}
   195→
   196→impl MemoryCache {
   197→    pub fn new() -> Self {
   198→        Self {
   199→            store: RwLock::new(std::collections::HashMap::new()),
   200→        }
   201→    }
   202→}
   203→
   204→#[async_trait]
   205→impl Cache for MemoryCache {
   206→    async fn get_bytes(&self, key: &str) -> anyhow::Result<Option<Vec<u8>>> {
   207→        let map = self.store.read().await;
   208→        if let Some((bytes, exp)) = map.get(key) {
   209→            if exp.elapsed() < Duration::from_secs(0) {
   210→                return Ok(None);
   211→            }
   212→            Ok(Some(bytes.clone()))
   213→        } else {
   214→            Ok(None)
   215→        }
   216→    }
   217→
   218→    async fn set_bytes(&self, key: &str, value: &[u8], ttl: Duration) -> anyhow::Result<()> {
   219→        let mut map = self.store.write().await;
   220→        map.insert(key.to_string(), (value.to_vec(), std::time::Instant::now() + ttl));
   221→        Ok(())
   222→    }
   223→}
