   225→/////////////////////////////////////////////////////////////////////////////
   226→// 5. SERVICE LAYER
   227→/////////////////////////////////////////////////////////////////////////////
   228→
   229→mod service {
   230→    use super::*;
   231→    use serde_json::to_vec;
   232→
   233→    /// Public facing façade that can be injected into controllers.
   234→    ///
   235→    /// Behind the scenes the service will:
   236→    ///     - Validate the pagination struct
   237→    ///     - Look for a cached page in Redis
   238→    ///     - On cache miss, query the repository and hydrate the cache
   239→    ///     - Emit structured tracing spans
   240→    pub struct LedgerEntryService<R: LedgerEntryRepository, C: Cache> {
   241→        repo:  R,
   242→        cache: C,
   243→        ttl:   Duration,
   244→    }
   245→
   246→    impl<R: LedgerEntryRepository, C: Cache> LedgerEntryService<R, C> {
   247→        pub fn new(repo: R, cache: C, ttl: Duration) -> Self {
   248→            Self { repo, cache, ttl }
   249→        }
   250→
   251→        /// Returns a paginated slice of ledger entries with caching applied.
   252→        #[instrument(
   253→            skip_all,
   254→            fields(
   255→                tenant = %tenant_id,
   256→                after = ?params.after,
   257→                before = ?params.before,
   258→                limit = params.limit
   259→            )
   260→        )]
   261→        pub async fn list_entries(
   262→            &self,
   263→            tenant_id: &str,
   264→            params: PageParams,
   265→        ) -> Result<Paged<LedgerEntry>, ServiceError> {
   266→            params.validate().map_err(ServiceError::Page)?;
   267→
   268→            // Compose a stable cache key – versioned for easy invalidation.
   269→            let cache_key = Self::cache_key(tenant_id, &params);
   270→
   271→            if let Some(bytes) = self.cache.get_bytes(&cache_key).await? {
   272→                debug!("cache hit for key={cache_key}");
   273→                let page: Paged<LedgerEntry> =
   274→                    serde_json::from_slice(&bytes).map_err(ServiceError::Internal)?;
   275→                return Ok(page);
   276→            }
   277→
   278→            debug!("cache miss for key={cache_key}");
   279→            let page = self.repo.fetch_page(tenant_id, &params).await?;
   280→            let serialized = to_vec(&page).map_err(ServiceError::Internal)?;
   281→            self.cache
   282→                .set_bytes(&cache_key, &serialized, self.ttl)
   283→                .await?;
   284→
   285→            Ok(page)
   286→        }
   287→
   288→        fn cache_key(tenant_id: &str, params: &PageParams) -> String {
   289→            let mut key = format!(
