   297→/// Minimal Redis cache backend implementation.
   298→#[cfg(all(feature = "response_caching", feature = "redis"))]
   299→pub struct RedisCache<B: ConnectionLike + Send + Sync + 'static>(pub tokio::sync::Mutex<B>);
   300→
   301→#[cfg(all(feature = "response_caching", feature = "redis"))]
   302→#[async_trait]
   303→impl<B> CacheBackend for RedisCache<B>
   304→where
   305→    B: ConnectionLike + Send + Sync + 'static,
   306→{
   307→    async fn get<T>(&self, key: &CacheKey) -> Result<Option<T>, CacheError>
   308→    where
   309→        T: for<'de> Deserialize<'de> + Send,
   310→    {
   311→        let redis_key = key.as_redis_key();
   312→        let mut conn = self.0.lock().await;
   313→        let data: Option<String> = conn.get(&redis_key).await?;
   314→        Ok(match data {
   315→            Some(s) => {
   316→                let parsed = serde_json::from_str::<T>(&s)?;
   317→                Some(parsed)
   318→            }
   319→            None => None,
   320→        })
   321→    }
   322→
   323→    async fn set<T>(
   324→        &self,
   325→        key: CacheKey,
   326→        value: &T,
   327→        ttl: Duration,
   328→    ) -> Result<(), CacheError>
   329→    where
   330→        T: Serialize + Send + Sync,
   331→    {
   332→        let redis_key = key.as_redis_key();
   333→        let payload = serde_json::to_string(value)?;
   334→        let mut conn = self.0.lock().await;
   335→        let _: () = conn
   336→            .set_ex::<_, _, ()>(&redis_key, payload, ttl.as_secs() as usize)
   337→            .await?;
   338→        Ok(())
   339→    }
   340→}
