     2→//! LedgerLink Nexus – Ledger Entry query pipeline
     3→//!
     4→//! This module contains everything required to expose a paginated,
     5→//! cache-aware “GET /v1/{tenant}/ledger-entries” REST/GraphQL endpoint.
     6→//! It demonstrates the MVVM-inspired layout used throughout the code
     7→//! base: View <-> View-Model <-> Domain Model <-> Repository.
     8→//!
     9→//! Dependencies (Cargo.toml excerpt for reference):
    10→//! ------------------------------------------------
    11→//! [dependencies]
    12→//! actix-web     = "4"
    13→//! async-trait   = "0.1"
    14→//! redis         = { version = "0.23", features = ["tokio-comp"] }
    15→//! rust_decimal  = { version = "1", features = ["serde-rust-false"] }
    16→//! serde         = { version = "1", features = ["derive"] }
    17→//! sqlx          = { version = "0.7", features = ["postgres", "runtime-tokio-native-tls", "uuid", "chrono", "macros"] }
    18→//! thiserror     = "1"
    19→//! tracing       = "0.1"
    20→//! uuid          = { version = "1", features = ["serde", "v4"] }
    21→//! validator     = { version = "0.16", features = ["derive"] }
    22→
    23→use std::time::Duration;
    24→
    25→use actix_web::{
    26→    http::header::{CacheControl, CacheDirective},
