    36→use uuid::Uuid;
    37→use validator::Validate;
    38→
    39→// ---------- Constants & helpers ---------------------------------------------------------------
    40→
    41→const DEFAULT_PAGE_SIZE: u32 = 50;
    42→const MAX_PAGE_SIZE: u32 = 500;
    43→const CACHE_TTL_SECONDS: usize = 45; // short-lived cache, safe for real-time ledgers
    44→
    45→// ---------- API View --------------------------------------------------------------------------
    46→
    47→/// Public wire format delivered to clients.
    48→#[derive(Debug, Serialize)]
    49→pub struct LedgerEntryView {
    50→    pub id: Uuid,
    51→    pub account_id: Uuid,
    52→    pub amount: Decimal,
    53→    pub currency: String,
    54→    #[serde(with = "chrono::serde::ts_seconds")]
