    67→// ---------- View-Model ------------------------------------------------------------------------
    68→
    69→/// Validated query parameters coming from the client.
    70→#[derive(Debug, Deserialize, Validate)]
    71→pub struct LedgerEntryQuery {
    72→    #[validate(range(min = 1))]
    73→    #[serde(default = "default_page")]
    74→    pub page: u32,
    75→
    76→    #[validate(range(min = 1, max = 500))]
