    86→}
    87→
    88→impl LedgerEntryQuery {
    89→    pub fn offset_limit(&self) -> (i64, i64) {
    90→        let offset = ((self.page.saturating_sub(1)) * self.per_page) as i64;
    91→        let limit = self.per_page as i64;
    92→        (offset, limit)
    93→    }
    94→}
