    98→#[derive(Debug)]
    99→pub struct LedgerEntry {
   100→    pub id: Uuid,
   101→    pub tenant_id: Uuid,
   102→    pub account_id: Uuid,
   103→    pub amount: Decimal,
   104→    pub currency: String,
   105→    pub booked_at: chrono::NaiveDateTime,
   106→}
