   148→    #[instrument(level = "debug", skip(self))]
   149→    async fn get<T: for<'de> Deserialize<'de> + Send>(
   150→        &self,
   151→        key: &str,
   152→    ) -> Result<Option<T>, CacheError> {
   153→        let mut conn = self.conn.lock().await;
   154→        let raw: Option<String> = conn.get(key).await?;
   155→        match raw {
   156→            None => Ok(None),
   157→            Some(json) => Ok(Some(serde_json::from_str(&json)?)),
   158→        }
   159→    }
