    52→// -----------------------------------------------------------------------------
    53→// Domain Model
    54→// -----------------------------------------------------------------------------
    55→
    56→/// Immutable ledger entry (domain model).
    57→#[derive(Debug, Clone)]
    58→pub struct LedgerEntry {
    59→    pub id:            Uuid,
    60→    pub account_id:    Uuid,
    61→    pub amount_minor:  i64,          // Monetary minor units (e.g., cents)
    62→    pub currency:      String,
    63→    pub entry_type:    EntryType,
    64→    pub created_at:    DateTime<Utc>,
    65→    pub description:   Option<String>,
    66→}
    67→
    68→/// Enum for debit / credit classification.
    69→#[derive(Debug, Copy, Clone, Serialize, Deserialize, sqlx::Type)]
    70→#[sqlx(type_name = "ledger_entry_type", rename_all = "lowercase")]
    71→pub enum EntryType {
