    76→// -----------------------------------------------------------------------------
    77→// DTO / View Model
    78→// -----------------------------------------------------------------------------
    79→
    80→/// External representation of a ledger entry.
    81→/// Keeps internal invariants hidden and provides
    82→/// forward-compatibility via versioned fields.
    83→#[derive(Debug, Serialize, Deserialize)]
    84→pub struct LedgerEntryView {
