    92→
    93→impl From<LedgerEntry> for LedgerEntryView {
    94→    fn from(src: LedgerEntry) -> Self {
    95→        let sign = if src.entry_type == EntryType::Debit { "-" } else { "" };
    96→        // Assume 2 decimal places for simplicity; a production system would
    97→        // leverage `rust_decimal` or similar.
    98→        let amount_major = (src.amount_minor as f64) / 100.0;
    99→        LedgerEntryView {
   100→            id:          src.id,
   101→            account_id:  src.account_id,
   102→            amount:      format!("{}{:.2} {}", sign, amount_major.abs(), src.currency),
   103→            direction:   src.entry_type,
   104→            created_at:  src.created_at,
   105→            description: src.description,
