   125→    pub fn new(page: u32, per_page: u32) -> Result<Self, LedgerError> {
   126→        if page == 0 {
   127→            return Err(LedgerError::validation("`page` must be >= 1"));
   128→        }
   129→        if per_page == 0 || per_page > MAX_PER_PAGE {
   130→            return Err(LedgerError::validation(&format!(
   131→                "`per_page` must be in 1..={MAX_PER_PAGE}"
   132→            )));
   133→        }
   134→        Ok(Self { page, per_page })
   135→    }
   136→
   137→    pub fn offset_limit(self) -> (i64, i64) {
   138→        (
   139→            ((self.page - 1) * self.per_page) as i64,
   140→            self.per_page as i64,
   141→        )
   142→    }
   143→}
