     2→//!
     3→//! Pagination, caching and response helpers for LedgerLink Nexus.
     4→//!
     5→//! This module is *framework agnostic* but ships with ready-made Actix‐Web glue to
     6→//! streamline JSON rendering, cursor pagination and HTTP cache controls.  Nothing here
     7→//! is Ledger-specific, so it can be re-used by any micro-service inside the Nexus
     8→//! constellation.
     9→
    10→use actix_web::{
    11→    get,
    12→    http::{header, HeaderValue, StatusCode},
    13→    web, HttpRequest, HttpResponse, ResponseError,
    14→};
    15→use anyhow::Context;
    16→use async_trait::async_trait;
    17→use chrono::NaiveDateTime;
    18→use deadpool_postgres::Pool;
    19→use serde::{Deserialize, Serialize};
    20→use sha2::{Digest, Sha256};
    21→use std::fmt::Display;
    22→use thiserror::Error;
    23→use tokio_postgres::Row;
    24→use validator::{Validate, ValidationError};
    25→
    26→/* -------------------------------------------------------------------------- */
    27→/*                               Pagination                                   */
    28→/* -------------------------------------------------------------------------- */
    29→
    30→/// Hard upper-bound enforced by validation layer.
    31→pub const MAX_PAGE_SIZE: u16 = 500;
    32→
    33→/// Cursor based pagination inspired by Relay spec.
    34→#[derive(Debug, Deserialize, Validate)]
    35→pub struct PaginationParams {
    36→    /// Opaque base64 cursor that points to the element *after* the last one from the
    37→    /// previous page.
    38→    #[validate(custom = "validate_cursor")]
    39→    pub after: Option<String>,
    40→
    41→    /// Amount of items to return, inclusive. Server rejects anything above
    42→    /// [`MAX_PAGE_SIZE`].
    43→    #[validate(range(min = 1, max = "MAX_PAGE_SIZE"))]
    44→    pub first: Option<u16>,
    45→}
    46→
    47→/// Custom validator for cursor format.
    48→fn validate_cursor(cursor: &str) -> Result<(), ValidationError> {
    49→    base64::decode(cursor)
    50→        .map(|_| ())
    51→        .map_err(|_| ValidationError::new("invalid_cursor"))
    52→}
    53→
    54→/// Relay-style pagination meta block.
    55→#[derive(Debug, Serialize)]
    56→pub struct PageInfo {
    57→    pub has_next_page: bool,
    58→    pub end_cursor: Option<String>,
    59→    pub total_count: Option<u64>,
    60→}
    61→
    62→/// Generic container returned by list endpoints.
    63→#[derive(Debug, Serialize)]
    64→pub struct Paginated<T> {
    65→    pub data: Vec<T>,
    66→    pub page_info: PageInfo,
    67→}
    68→
    69→/// Repository structs that implement this trait can be plugged into the generic
    70→/// [`paginate`] helper.
    71→#[async_trait]
    72→pub trait Pageable {
    73→    type Item: Send + Sync + Serialize;
    74→
    75→    async fn fetch_page(
    76→        &self,
    77→        cursor: Option<&str>,
    78→        page_size: u16,
    79→    ) -> anyhow::Result<(Vec<Self::Item>, Option<String>, bool)>;
    80→}
    81→
    82→/// Thin convenience wrapper that orchestrates cursor pagination flow.
    83→pub async fn paginate<R>(
    84→    repo: &R,
    85→    params: &PaginationParams,
    86→) -> anyhow::Result<Paginated<R::Item>>
    87→where
    88→    R: Pageable + Sync,
    89→{
    90→    let size = params.first.unwrap_or(50);
    91→    let (records, end_cursor, has_next_page) =
    92→        repo.fetch_page(params.after.as_deref(), size).await?;
    93→    Ok(Paginated {
    94→        data: records,
    95→        page_info: PageInfo {
    96→            has_next_page,
    97→            end_cursor,
    98→            total_count: None,
    99→        },
   100→    })
   101→}
   102→
   103→/* -------------------------------------------------------------------------- */
   104→/*                             Cache Directives                               */
   105→/* -------------------------------------------------------------------------- */
   106→
   107→/// Describes how HTTP/GraphQL clients may cache a particular response.
   108→#[derive(Debug, Clone, Copy)]
   109→pub enum CacheDirective {
   110→    /// Content never changes and can be stored forever.
   111→    Immutable,
   112→    /// Content may be reused for the specified amount of seconds.
   113→    MaxAge(u32),
   114→    /// Response must not be cached.
   115→    NoCache,
   116→}
   117→
   118→impl CacheDirective {
   119→    fn to_header_value(self) -> HeaderValue {
   120→        match self {
   121→            CacheDirective::Immutable => {
   122→                HeaderValue::from_static("public, max-age=31536000, immutable")
   123→            }
   124→            CacheDirective::MaxAge(s) => {
   125→                HeaderValue::from_str(&format!("public, max-age={s}")).unwrap()
   126→            }
   127→            CacheDirective::NoCache => {
   128→                HeaderValue::from_static("no-cache, no-store, must-revalidate")
   129→            }
   130→        }
   131→    }
   132→}
   133→
   134→/* -------------------------------------------------------------------------- */
   135→/*                        Unified JSON response helper                        */
   136→/* -------------------------------------------------------------------------- */
   137→
   138→/// Convenience wrapper that handles JSON serialization, [`ETag`] calculation and the
   139→/// `Cache-Control` header.
   140→pub struct JsonResponse<T> {
   141→    payload: T,
   142→    cache: CacheDirective,
   143→}
   144→
   145→impl<T> JsonResponse<T>
   146→where
   147→    T: Serialize,
   148→{
   149→    pub fn new(payload: T, cache: CacheDirective) -> Self {
   150→        Self { payload, cache }
   151→    }
