   158→        let mut hasher = Sha256::new();
   159→        hasher.update(&serialized);
   160→        let tag = format!(r#"W/"{:x}""#, hasher.finalize());
   161→        let etag = HeaderValue::from_str(&tag).unwrap();
   162→
   163→        // Handle If-None-Match pre-condition.
   164→        if let Some(client_tag) = req.headers().get(header::IF_NONE_MATCH) {
