   166→                return Ok(HttpResponse::NotModified()
   167→                    .insert_header((header::ETAG, etag))
   168→                    .insert_header((header::CACHE_CONTROL, self.cache.to_header_value()))
   169→                    .finish());
   170→            }
   171→        }
   172→
   173→        Ok(HttpResponse::Ok()
   174→            .insert_header((header::ETAG, etag))
   175→            .insert_header((header::CACHE_CONTROL, self.cache.to_header_value()))
   176→            .content_type("application/json")
   177→            .body(serialized))
   178→    }
   179→}
