   183→/* -------------------------------------------------------------------------- */
   184→
   185→#[derive(Debug, Error)]
   186→pub enum ApiError {
   187→    #[error("validation error: {0}")]
   188→    Validation(#[from] validator::ValidationErrors),
   189→    #[error("{0}")]
   190→    Anyhow(#[from] anyhow::Error),
   191→}
   192→
   193→impl ResponseError for ApiError {
   194→    fn status_code(&self) -> StatusCode {
   195→        match self {
   196→            ApiError::Validation(_) => StatusCode::BAD_REQUEST,
   197→            ApiError::Anyhow(_) => StatusCode::INTERNAL_SERVER_ERROR,
   198→        }
   199→    }
   200→
   201→    fn error_response(&self) -> HttpResponse {
   202→        HttpResponse::build(self.status_code()).json(serde_json::json!({
   203→            "error": self.to_string()
   204→        }))
   205→    }
   206→}
   207→
   208→/* -------------------------------------------------------------------------- */
   209→/*                    Domain model & repository example                       */
   210→/* -------------------------------------------------------------------------- */
   211→
   212→/// Simplified Ledger Entry domain aggregate.
   213→#[derive(Debug, Serialize)]
   214→pub struct LedgerEntry {
   215→    id: i64,
   216→    description: String,
   217→    amount_cents: i64,
   218→    created_at: NaiveDateTime,
   219→}
   220→
   221→/// POC implementation using [`tokio_postgres`] + [`deadpool_postgres`].
   222→pub struct LedgerEntryRepository {
   223→    pool: Pool,
   224→}
   225→
   226→impl LedgerEntryRepository {
   227→    pub fn new(pool: Pool) -> Self {
   228→        Self { pool }
   229→    }
   230→}
   231→
   232→#[async_trait]
   233→impl Pageable for LedgerEntryRepository {
   234→    type Item = LedgerEntry;
   235→
   236→    async fn fetch_page(
   237→        &self,
   238→        cursor: Option<&str>,
   239→        page_size: u16,
