   249→            .query(
   250→                "
   251→                SELECT id, description, amount_cents, created_at
   252→                  FROM ledger_entries
   253→                 WHERE id > $1
   254→              ORDER BY id ASC
   255→                 LIMIT $2 + 1
   256→                ",
   257→                &[&cursor_id, &(page_size as i64)],
