   278→        let end_cursor = data
   279→            .last()
   280→            .map(|e| base64::encode(e.id.to_string()));
   281→
   282→        Ok((data, end_cursor, has_next_page))
   283→    }
   284→}
   285→
   286→/* -------------------------------------------------------------------------- */
   287→/*                               HTTP Handler                                 */
   288→/* -------------------------------------------------------------------------- */
   289→
   290→#[get("/v1/ledger_entries")]
   291→async fn list_ledger_entries(
   292→    repo: web::Data<LedgerEntryRepository>,
   293→    params: web::Query<PaginationParams>,
