#[derive(Debug, Serialize)]
pub struct ErrorResponse {
    pub error: ErrorDetail,
}

#[derive(Debug, Serialize)]
pub struct ErrorDetail {
    #[serde(rename = "type")]
    pub error_type: String,
    pub message: String,
}

impl AppError {
    pub fn status_code(&self) -> StatusCode {
        match self {
            AppError::ValidationError(_) | AppError::PaginationError(_) |
            AppError::ValidatorError(_) => StatusCode::BAD_REQUEST,
            AppError::NotFound(_) => StatusCode::NOT_FOUND,
            AppError::Unauthorized => StatusCode::UNAUTHORIZED,
            AppError::Forbidden(_) => StatusCode::FORBIDDEN,
            AppError::Database(_) | AppError::Cache(_) | AppError::Serialization(_) |
            AppError::Repository(_) | AppError::Internal(_) | AppError::Anyhow(_) =>
                StatusCode::INTERNAL_SERVER_ERROR,
            AppError::Timeout(_) => StatusCode::GATEWAY_TIMEOUT,
            AppError::RateLimitExceeded(_) => StatusCode::TOO_MANY_REQUESTS,
            AppError::ServiceUnavailable(_) => StatusCode::SERVICE_UNAVAILABLE,
        }
    }

    pub fn error_type(&self) -> &'static str {
        match self {
            AppError::ValidationError(_) | AppError::ValidatorError(_) => "validation",
            AppError::NotFound(_) => "not_found",
            AppError::Unauthorized => "unauthorized",
            AppError::Forbidden(_) => "forbidden",
            AppError::Database(_) => "database",
            AppError::Cache(_) => "cache",
            AppError::Serialization(_) => "serialization",
            AppError::PaginationError(_) => "pagination",
            AppError::Repository(_) | AppError::Internal(_) | AppError::Anyhow(_) => "internal",
            AppError::Timeout(_) => "timeout",
            AppError::RateLimitExceeded(_) => "rate_limit",
            AppError::ServiceUnavailable(_) => "service_unavailable",
        }
    }
}

impl IntoResponse for AppError {
    fn into_response(self) -> Response {
        let status = self.status_code();
        let body = Json(ErrorResponse {
            error: ErrorDetail {
                error_type: self.error_type().to_string(),
                message: self.to_string(),
            },
        });
        (status, body).into_response()
    }
}

/// Type alias for Results using AppError
pub type AppResult<T> = Result<T, AppError>;

// From implementations for common types
impl From<String> for AppError {
    fn from(s: String) -> Self { AppError::Internal(s) }
}

impl From<&str> for AppError {
    fn from(s: &str) -> Self { AppError::Internal(s.to_string()) }
}

impl From<tokio_postgres::Error> for AppError {
    fn from(err: tokio_postgres::Error) -> Self { AppError::Repository(err.to_string()) }
}

// Helper constructors
impl AppError {
    pub fn validation<S: Into<String>>(msg: S) -> Self { AppError::ValidationError(msg.into()) }
    pub fn not_found<S: Into<String>>(resource: S) -> Self { AppError::NotFound(resource.into()) }
    pub fn repository<S: Into<String>>(msg: S) -> Self { AppError::Repository(msg.into()) }
    pub fn internal<S: Into<String>>(msg: S) -> Self { AppError::Internal(msg.into()) }
    pub fn pagination<S: Into<String>>(msg: S) -> Self { AppError::PaginationError(msg.into()) }
}
