/// Assert that a response is an error with the expected type and status
pub async fn assert_error_response(
    resp: Response,
    expected_status: StatusCode,
    expected_type: &str,
) -> Result<ApiErrorResponse> {
    assert_eq!(resp.status(), expected_status, "Unexpected HTTP status");

    let bytes = resp.bytes().await.context("Reading error response body")?;
    let error_resp: ApiErrorResponse = serde_json::from_slice(&bytes)
        .context("Decoding error JSON")?;

    assert_eq!(
        error_resp.error.error_type, expected_type,
        "Unexpected error type"
    );

    Ok(error_resp)
}

